import{_ as a,a as e}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const D=JSON.parse('{"title":"WebDAV 配置与访问（beta测试）","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Safety/webdav-site-access.md","filePath":"cn/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),o={name:"cn/Safety/webdav-site-access.md"};function s(h,t,n,b,p,c){return l(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="webdav-配置与访问-beta测试" tabindex="-1">WebDAV 配置与访问（beta测试） <a class="header-anchor" href="#webdav-配置与访问-beta测试" aria-label="Permalink to &quot;WebDAV 配置与访问（beta测试）&quot;">​</a></h1><p>安全设置里的 WebDAV 用来把图床开放成一个 WebDAV 访问入口。</p><p>配置后，你可以在 Windows、macOS、手机文件管理器或支持 WebDAV 的客户端里，把图床当成一个远程文件夹使用，直接浏览、上传、删除和管理文件。</p><p>这里的 WebDAV 是“站点访问入口”，不是上传设置里的“WebDAV 存储渠道”。上传渠道里的 WebDAV 是把第三方 WebDAV 服务当作存储位置；安全设置里的 WebDAV 是让你的图床站点对外提供 WebDAV 访问。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>进入后台后，打开：</p><p>系统配置 → 安全设置 → WebDAV</p><p>页面里可以看到这些配置：</p><ul><li>启用</li><li>用户名</li><li>密码</li><li>图像加载模式</li><li>默认渠道</li></ul><h2 id="这个功能有什么用" tabindex="-1">这个功能有什么用 <a class="header-anchor" href="#这个功能有什么用" aria-label="Permalink to &quot;这个功能有什么用&quot;">​</a></h2><p>开启 WebDAV 后，系统会提供一个固定访问地址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/dav</span></span></code></pre></div><p>你可以用这个地址连接图床文件目录。</p><p>适合这些场景：</p><ul><li>在电脑文件管理器里直接查看图床文件。</li><li>把图片拖进 WebDAV 目录完成上传。</li><li>在本地像整理文件夹一样整理图床目录。</li><li>使用支持 WebDAV 的软件同步或管理图片。</li><li>不打开后台，也能通过文件管理器访问图床内容。</li></ul><h2 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h2><h3 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h3><p>开启后，WebDAV 入口才会生效。</p><p>关闭后，客户端无法通过 WebDAV 连接图床。</p><h3 id="用户名和密码" tabindex="-1">用户名和密码 <a class="header-anchor" href="#用户名和密码" aria-label="Permalink to &quot;用户名和密码&quot;">​</a></h3><p>用户名和密码是 WebDAV 客户端连接时使用的账号。</p><p>建议单独设置一组 WebDAV 专用账号，不要和后台管理密码、上传密码混用。</p><p>如果没有填写用户名或密码，WebDAV 客户端无法正常连接。</p><h3 id="图像加载模式" tabindex="-1">图像加载模式 <a class="header-anchor" href="#图像加载模式" aria-label="Permalink to &quot;图像加载模式&quot;">​</a></h3><p>图像加载模式决定 WebDAV 客户端读取图片时优先使用哪种图片地址。</p><p>常见选择：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td>智能加载</td><td>系统根据场景自动选择，日常使用建议选择这个</td></tr><tr><td>原图</td><td>优先读取原始图片</td></tr><tr><td>缩略图</td><td>优先读取缩略图，适合快速预览</td></tr></tbody></table><p>如果不确定怎么选，保持“智能加载”即可。</p><h3 id="默认渠道" tabindex="-1">默认渠道 <a class="header-anchor" href="#默认渠道" aria-label="Permalink to &quot;默认渠道&quot;">​</a></h3><p>默认渠道用于 WebDAV 上传文件。</p><p>当你通过 Windows 或其他 WebDAV 客户端把文件复制到图床目录时，系统会把文件上传到这里选择的默认上传渠道。</p><p>如果没有选择默认渠道，WebDAV 可以用于浏览，但上传文件时可能会失败。</p><h2 id="在-windows-11-中访问" tabindex="-1">在 Windows 11 中访问 <a class="header-anchor" href="#在-windows-11-中访问" aria-label="Permalink to &quot;在 Windows 11 中访问&quot;">​</a></h2><p>Windows 11 可以把 WebDAV 添加成网络位置。</p><p>操作步骤：</p><ol><li>打开“此电脑”。</li><li>选择“添加一个网络位置”。</li><li>地址填写 <code>https://你的域名/dav</code>。</li><li>按提示输入 WebDAV 用户名和密码。</li><li>完成后，就可以在资源管理器里打开这个 WebDAV 目录。</li></ol><p><img src="'+a+'" alt="Windows 11 添加 WebDAV" loading="lazy"></p><p>添加完成后，Windows 资源管理器里会显示 WebDAV 目录。你可以像访问普通文件夹一样打开、复制和管理文件。</p><p><img src="'+e+'" alt="WebDAV 在 Windows 中的显示效果" loading="lazy"></p><h2 id="可以进行哪些操作" tabindex="-1">可以进行哪些操作 <a class="header-anchor" href="#可以进行哪些操作" aria-label="Permalink to &quot;可以进行哪些操作&quot;">​</a></h2><p>WebDAV 连接成功后，通常可以进行这些操作：</p><ul><li>查看文件和文件夹。</li><li>上传文件。</li><li>新建文件夹。</li><li>重命名文件或文件夹。</li><li>移动文件。</li><li>删除文件。</li></ul><p>WebDAV 更适合日常访问和少量文件管理。大量文件移动、批量删除或复杂整理，建议在后台管理页面里操作。</p><h2 id="登录设备管理" tabindex="-1">登录设备管理 <a class="header-anchor" href="#登录设备管理" aria-label="Permalink to &quot;登录设备管理&quot;">​</a></h2><p>WebDAV 连接成功后，也会出现在“登录设备管理”的 WebDAV 页签里。</p><p>你可以在那里查看 WebDAV 客户端的登录设备，并在需要时让旧设备下线。</p><p>如果你修改了 WebDAV 用户名或密码，旧客户端需要重新登录。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="windows-一直要求输入账号密码" tabindex="-1">Windows 一直要求输入账号密码 <a class="header-anchor" href="#windows-一直要求输入账号密码" aria-label="Permalink to &quot;Windows 一直要求输入账号密码&quot;">​</a></h3><p>可以依次检查：</p><ul><li>地址是否填写为 <code>https://你的域名/dav</code>。</li><li>用户名和密码是否和后台 WebDAV 配置一致。</li><li>WebDAV 是否已经启用。</li><li>站点是否可以通过 HTTPS 正常访问。</li></ul><h3 id="能浏览-但上传失败" tabindex="-1">能浏览，但上传失败 <a class="header-anchor" href="#能浏览-但上传失败" aria-label="Permalink to &quot;能浏览，但上传失败&quot;">​</a></h3><p>通常需要检查“默认渠道”。</p><p>WebDAV 上传文件时需要一个默认上传渠道。如果默认渠道没有设置、被禁用或配置不可用，上传可能会失败。</p><h3 id="访问速度不稳定" tabindex="-1">访问速度不稳定 <a class="header-anchor" href="#访问速度不稳定" aria-label="Permalink to &quot;访问速度不稳定&quot;">​</a></h3><p>WebDAV 的体验会受客户端、网络、图片数量和默认上传渠道影响。</p><p>如果目录文件非常多，建议先按文件夹整理，避免在同一个目录里放入过多文件。</p><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><ul><li>使用 HTTPS 访问 WebDAV。</li><li>设置强密码。</li><li>不要把 WebDAV 密码发给不可信的人。</li><li>不使用时可以关闭 WebDAV。</li><li>定期在登录设备管理里清理不用的 WebDAV 设备。</li></ul><h2 id="webdav-上传文件大小" tabindex="-1">WebDAV 上传文件大小 <a class="header-anchor" href="#webdav-上传文件大小" aria-label="Permalink to &quot;WebDAV 上传文件大小&quot;">​</a></h2><p>WebDAV 客户端上传不支持网页端的大文件分块流程。超过下表大小时，请改用网页上传。</p><table tabindex="0"><thead><tr><th>默认上传渠道</th><th style="text-align:right;">WebDAV 单文件建议上限</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>HuggingFace</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',62)])])}const A=i(o,[["render",s]]);export{D as __pageData,A as default};
